import * as appDom from '@mui/toolpad-core/appDom';
import { RuntimeState } from './types';

export interface CreateRuntimeStateParams {
  dom: appDom.AppDom;
}

export default function createRuntimeState({ dom }: CreateRuntimeStateParams): RuntimeState {
  return {
    dom: appDom.createRenderTree(dom),
  };
}
/**
 * Returns a hash code for a string.
 * (Compatible to Java's String.hashCode())
 *
 * The hash code for a string object is computed as
 *     s[0]*31^(n-1) + s[1]*31^(n-2) + ... + s[n-1]
 * using number arithmetic, where s[i] is the i th character
 * of the given string, n is the length of the string,
 * and ^ indicates exponentiation.
 * (The hash value of the empty string is zero.)
 *
 * Do not use in a security critical context.
 *
 * @see https://gist.github.com/hyamamoto/fd435505d29ebfa3d9716fd2be8d42f0
 */
export default function insecureHash(str: string) {
  let h = 0;
  for (let i = 0; i < str.length; i += 1) {
    // eslint-disable-next-line no-bitwise
    h = (Math.imul(31, h) + str.charCodeAt(i)) | 0;
  }
  return h;
}
import prettier from 'prettier';
import parserBabel from 'prettier/parser-babel';

const DEFAULT_OPTIONS = {
  parser: 'babel-ts',
  plugins: [parserBabel],
};

/**
 * get prettier config file
 */
export async function resolvePrettierConfig(filePath: string) {
  const config = await prettier.resolveConfig(filePath);
  return config;
}

/**
 * Formats a javascript source with `prettier`.
 */
export async function format(code: string, filePath: string): Promise<string> {
  const readConfig = await resolvePrettierConfig(filePath);
  return prettier.format(code, {
    ...readConfig,
    ...DEFAULT_OPTIONS,
  });
}

/**
 * Formats a javascript expression with `prettier`.
 */
export async function formatExpression(
  code: string,
  config?: prettier.Options | null,
): Promise<string> {
  const formatted = await prettier.format(code, {
    ...config,
    ...DEFAULT_OPTIONS,
    semi: false,
  });

  // There's no mode to format expressions in prettier. It will insert a semicolon in front
  // in certain occasions. See https://github.com/prettier/prettier/issues/2841
  return formatted.replace(/^;/, '');
}

/**
 * Formats a javascript expression with `prettier`, if it's valid.
 */
export async function tryFormatExpression(
  code: string,
  config?: prettier.Options,
): Promise<string> {
  try {
    return await formatExpression(code, config);
  } catch (err) {
    return code;
  }
}
export type ParsedFunctionId =
  | {
      file: string;
      handler?: undefined;
    }
  | {
      file: string;
      handler: string;
    };

export function parseLegacyFunctionId(id: string): ParsedFunctionId {
  if (!id) {
    return { file: 'functions.ts' };
  }
  const [file, handler] = id.split('#');
  return handler ? { file, handler } : { file: 'functions.ts', handler: file };
}

export function parseFunctionId(id: string): ParsedFunctionId {
  const [file, handler] = id.split('#');
  return handler ? { file, handler } : { file };
}

export function serializeFunctionId({ file, handler }: ParsedFunctionId): string {
  return handler ? `${file}#${handler}` : file;
}

export function transformLegacyFunctionId(id: string): string {
  if (!id) {
    return '';
  }
  const [file, handler] = id.split('#');
  return handler ? id : `functions.ts#${file}`;
}
import { BindableAttrValue } from '@mui/toolpad-core';
import { ensureSuffix } from '@mui/toolpad-utils/strings';
import { Maybe } from '@mui/toolpad-utils/types';
import { Authentication, RestConnectionParams } from './types';
import type { RuntimeConfig } from '../../types';

export const HTTP_NO_BODY = new Set(['GET', 'HEAD']);

export function getAuthenticationHeaders(auth: Maybe<Authentication>): [string, string][] {
  if (!auth) {
    return [];
  }

  switch (auth.type) {
    case 'basic':
      return [
        [
          'Authorization',
          `Basic ${Buffer.from(`${auth.user}:${auth.password}`, 'utf-8').toString('base64')}`,
        ],
      ];
    case 'bearerToken':
      return [['Authorization', `Bearer ${auth.token}`]];
    case 'apiKey':
      return [[auth.header, auth.key]];
    default:
      throw new Error(`Unsupported authentication type "${(auth as Authentication).type}"`);
  }
}

export function parseBaseUrl(baseUrl: string): URL {
  const parsedBase = new URL(baseUrl);
  parsedBase.pathname = ensureSuffix(parsedBase.pathname, '/');
  parsedBase.search = '';
  parsedBase.hash = '';
  return parsedBase;
}

export function getDefaultUrl(
  config: RuntimeConfig,
  connection?: RestConnectionParams | null,
): BindableAttrValue<string> {
  const baseUrl = connection?.baseUrl;

  return baseUrl
    ? ''
    : new URL('/static/movies.json', config.externalUrl || window.location.href).href;
}
